import{_ as s,o as r,c as a,a as p,b as t,N as e}from"./chunks/plugin-vue_export-helper.B0FdOn3A.js";const m=JSON.parse('{"title":"Стрессоустойчивость","description":"","frontmatter":{"title":"Стрессоустойчивость","date":"2020-09-26T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-26-stress-tolerance.md","filePath":"posts/2020-09-26-stress-tolerance.md"}'),i={name:"posts/2020-09-26-stress-tolerance.md"};function l(u,o,n,c,q,_){return r(),a("div",null,[...o[0]||(o[0]=[p("<p>Это, наверное, тот самый важный навык, которого мне не хватает. На одном из собеседований на стандартный вопрос &quot;А как у вас со стрессоустойчивостью&quot; я на голубом глазу ответил что я не стрессоустойчив, чем вызвал у собеседующего поток нравоучений. Стресс, тем не менее, неотъемлемая часть жизни.</p><p>Этой статьёй я попробую немного разобраться в этом вопросе.</p><p>За последние три года я объективно пережил столько стресса и отчаяния, сколько не было за всю мою прошедшую жизнь (а я пережил 90-е в Тольятти). Начиная от переездов и пожара, заканчивая ремонтом и проблемами со здоровьем и работой.</p><p>Да, я крепкий человек. В английском есть подходящее слово &quot;tenance&quot; - способность ухватиться за что-то и держать это крепко. Выкручиваясь из разных ситуаций, в некоторые из которых я сам себя привёл гиперответственностью, верностью своему слову и решениям, я продолжал упорствовать и жрать кактус.</p><p>Но это сложно назвать стрессоустойчивостью. Наблюдая за людьми, я замечаю, что некоторые люди по-другому реагируют на стресс, они чувствуют себя энергичнее под давлением, не устают, не ноют и не агрессируют. В ютюб-шоу &quot;СтопХам&quot; это всё видно очень наглядно, поведение людей в ситуации когда всё идёт не так как им хочется очень разное, кто-то конфликтует, кто-то хитрит, а кто-то просто спокойно разворачивается и едет как нужно. Если бы все были стрессоустойчивые, шоу бы не получилось.</p><p>Итак, мы наткнулись на первый важный аспект неустойчивости - убежденность в своей правоте, &quot;всё должно быть так, как я хочу&quot;.</p><p>Ещё один стрессоген - осознанное принятие жизненных решений - выбрать ту работу или эту, бить или бежать, тот человек или этот. Тревожный мозг в фоновом режиме перебирает все негативные варианты развития событий. Лично я в какой-то момент просто устаю и выбираю не решать, успокаиваюсь, а потом просто думаю о том, что же мне на самом деле нужно.</p><p>Я собрал несколько техник по профилактическому развитию стрессоустойчивости из интернета. Их можно выполнять в спокойные периоды для тренировки:</p><ul><li><strong>Самообразование -</strong> вас никто никуда не гонит, можно делать подходы в удобное время и развивать устойчивость при решении проблем.</li><li><strong>Почаще просите -</strong> регулируйте уровень стресса прося в ситуациях когда возможность отказа велика.</li><li><strong>Выйдите из зоны комфорта -</strong> да, когда вы слишком долго в комфорте, ваша стрессоустойчивость страдает - простым языком, найдите среду где вы будете &quot;чувствовать себя мудаком&quot;, где все кажутся лучше чем вы в чем-то. Важно также уметь собрать обратную связь.</li><li><strong>Ведите дневник энергии и эмоционального состояния -</strong> со временем вы поймете что влияет на ваш уровень энергии и сможете сами управлять её уровнем, понимая как её правильно восстанавливать и когда вы наиболее наполнены чтобы распределять задачи конструктивно. Рефлексируйте временами, это помогает быть более уверенным в принятии решений.</li></ul><p>В острые периоды, когда кажется что конца и края этому нет, важно уметь переключаться на режим &quot;дорога возникает под ногами идущего&quot;, &quot;this too shall pass&quot;, это помогает разгрузить мозг и не поддаваться панике, сфокусироваться на себе и на том, что на данный момент поддается контролю.</p><p>После стрессовой ситуации, даже если вы не ответственны за её создание, важно подумать о том что вы могли бы сделать по-другому и о том, как вы привыкли реагировать в таких ситуациях. Потратьте некоторое время, оно воздастся в будущем.</p><p>В целом, стратегия проста:</p><ul><li>Оценивайте свои <strong>поступки</strong></li><li>Поддерживайте позитивный и конструктивный настрой</li><li>Получайте обратную связь</li><li>Передохните чтобы сменить направление</li><li>Оставьте ситуацию в прошлом</li></ul><p>Лично меня в периоды стресса раздражают фразы &quot;если судьба приподнесла вам лимоны, сделайте из них лимонад&quot;, &quot;думай позитивно, стакан всегда наполовину полон, всегда&quot;, &quot;узбагойся&quot;, и тд. Это обесценивание проблемы и пассивный подход. Если проблема есть, значит за ней что-то ценное. В психологии есть поняние &quot;интеграция тени&quot;, оно заключается в том, чтобы подсвечивать тёмные стороны своей личности и осваивать их.</p>",14),t("iframe",{frameborder:"0",style:{border:"none",width:"100%",height:"180px"},width:"100%",height:"180",src:"https://music.yandex.ru/iframe/#track/30767185/6554921"},[e("Слушайте "),t("a",{href:"https://music.yandex.ru/album/6554921/track/30767185"},"Думай позитивно"),e(" — "),t("a",{href:"https://music.yandex.ru/artist/218095"},"Кровосток"),e(" на Яндекс.Музыке")],-1)])])}const h=s(i,[["render",l]]);export{m as __pageData,h as default};
